function extractKeysAndValues(obj, subtopic) {
    for (let key in obj) {

        // If the value is an object, recursively extract keys and values
        if (typeof obj[key] === 'object' && obj[key] !== null) {
            extractKeysAndValues(obj[key], subtopic.concat("/", key));

        }
        else {
            //console.log(`Key: ${key}, Value: ${obj[key]}`);
            let msgtoSend = { payload: {} };
            msgtoSend.payload = obj[key];
            msgtoSend.topic = subtopic.concat("/", key);
            // console.log(msgtoSend)
            node.send(msgtoSend)
        }
    }
}

function sendTimestamp(topic) {
    let msgtoSend = { payload: {} };
    msgtoSend.payload = new Date();
    msgtoSend.topic = topic.concat("/", "timestamp");
    node.send(msgtoSend)
}

