function extractKeysAndValues(obj, subtopic) {
    for (let key in obj) {

        // If the value is an object, recursively extract keys and values
        if (typeof obj[key] === 'object' && obj[key] !== null) {
            extractKeysAndValues(obj[key], subtopic.concat("/", key));

        }
        else {
            //console.log(`Key: ${key}, Value: ${obj[key]}`);
            let msgtoSend = { payload: {} };
            msgtoSend.payload = obj[key];
            msgtoSend.topic = subtopic.concat("/", key);
            //console.log(msgtoSend)
            node.send([null,msgtoSend, null])
        }
    }
}

function sendTimestamp(topic,date) {
    let msgtoSend = { payload: {} };
    msgtoSend.payload = date;
    msgtoSend.topic = topic.concat("/", "timestamp");
    node.send([null,msgtoSend])
}

function getCurrentTariff(now) {
    const NT = false
    const HT = true
    const currentMonth = now.getMonth(); // 0-11 (Jan-Dec)
    const currentHour = now.getHours(); // 0-23
    const currentWeekDay = now.getDay(); // // 0 = Sunday, 1 = Monday, ..., 6 = Saturday
    let retVal = HT;
    // Determine if we're in winter (Oct-Mar) or summer (Apr-Sept)
    const isWinter = currentMonth >= 9 || currentMonth <= 2; // Oct(9)-Mar(2)
    const isWorkDay = currentWeekDay >= 1 || currentWeekDay <= 5 // Monday(1) - Friday (5)

    if (isWorkDay) {
        //Montag bis Freitag von 20.00 bis 7.00 Uhr
        if (currentHour >= 20 || currentHour < 7) {
            retVal = NT;
        }
    } else {
        retVal = NT;
    }

    return { 

        "highTariff": retVal,
        "currentHour": currentHour,
        "currentWeekDay": currentWeekDay,
        "date": now,
        "timezoneOffset": now.getTimezoneOffset()
    }
}

