var addressesToRead = [0];
var messages = [];
var unitId = 5;

for (var i = 0; i < addressesToRead.length; i++) {
    for (var j=1; j<3; j++) {
    var address = addressesToRead[i];
    var message = {
        payload: {
            value: msg.payload,
            fc: 4,         // Function code for Read Holding Registers
            unitid: j,     // Modbus Unit-ID
            address: address,
            quantity: 88 // Set quantity to the length of addressesToRead
        }
    };
    messages.push(message);
    }    
}

return messages;

var valueArray = msg.payload.data;
var numPairs = valueArray.length / 2; // Calculate the number of pairs in the array

// Check if the array contains a multiple of 2 values (pairs)
if (numPairs >= 3) {
    // Initialize an object to store the calculated values with the D0001, D0002, ... notation
    var result = {};

    // Loop through the pairs and calculate values
    for (var i = 0; i < 3; i++) {
        // Calculate the offset for the current pair of 16-bit values
        var offset = i * 2;

        // Combine the 16-bit values into a 32-bit integer
        var combinedValue = (valueArray[offset] << 16) | valueArray[offset + 1];

        // Convert the combined 32-bit integer to a floating-point value
        var buffer = Buffer.alloc(4); // Create a buffer of 4 bytes
        buffer.writeInt32BE(combinedValue, 0); // Write the combined value as a big-endian 32-bit integer

        // Generate the key in the D0001, D0002, ... format
        var key = "D" + ("000" + (i + 1)).slice(-4);

        // Store the floating-point value in the result object with the key
        result[key] = parseFloat(buffer.readFloatBE(0).toFixed(4));
    }

    // Set the result as the new payload
    msg.payload = result;
} else {
    node.warn("Expected an array with at least three pairs of 16-bit values.");
    return null;
}

return msg;

